<script setup>defineProps({analysis:Object,loading:Boolean,error:String});defineEmits(['generate'])</script><template><section class="advice"><h3>Qwen 个性化营养建议</h3><button class="primary-button" :disabled="loading" @click="$emit('generate')">{{loading?'生成中...':analysis?'重新生成':'生成个性化建议'}}</button><p v-if="error" class="error-alert">{{error}}</p><div v-if="analysis"><p><strong>{{analysis.summary}}</strong></p><ul><li v-for="x in analysis.key_findings" :key="x">{{x}}</li></ul><ul><li v-for="x in analysis.suggestions" :key="x">{{x}}</li></ul><p>{{analysis.follow_up}}</p><p>{{analysis.disclaimer}}</p></div></section></template><style scoped>.advice{display:grid;gap:12px;padding:18px;border:1px solid #b9dce9;border-radius:10px;background:#f4fbfe}.advice p{margin:0}</style>
